  `role` varchar(45) DEFAULT NULL,
  `digital_signature` text DEFAULT NULL,
  `passport_url` varchar(500) DEFAULT NULL COMMENT 'Profile picture/passport photo URL',
  `is_activated` tinyint(1) DEFAULT 0 COMMENT 'Account activation status (0=not activated, 1=activated)',
  `activation_otp` varchar(6) DEFAULT NULL COMMENT 'OTP for account activation',
  `activation_otp_expires_at` datetime DEFAULT NULL COMMENT 'OTP expiry time',
  `activation_otp_attempts` int(11) DEFAULT 0 COMMENT 'Number of failed OTP attempts',
  `must_change_password` tinyint(1) DEFAULT 0 COMMENT 'Force password change on next login',
  `first_login_completed` tinyint(1) DEFAULT 0 COMMENT 'Whether user completed first login setup',
  `password_changed_at` datetime DEFAULT NULL COMMENT 'Last password change timestamp',
  `activated_at` datetime DEFAULT NULL COMMENT 'Account activation timestamp',
  `activation_method` enum('otp_sms','otp_email','manual_admin') DEFAULT NULL COMMENT 'How account was activated',
  `allowed_features` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`allowed_features`)),
  `subscription_plan` varchar(50) DEFAULT 'standard',
  PRIMARY KEY (`id`),
  UNIQUE KEY `id` (`id`),
  UNIQUE KEY `id_2` (`id`),
  UNIQUE KEY `email` (`email`,`school_id`),
  KEY `school_id` (`school_id`),
  KEY `idx_is_activated` (`is_activated`),
  KEY `idx_must_change_password` (`must_change_password`),
  KEY `idx_first_login_completed` (`first_login_completed`)
) ENGINE=InnoDB AUTO_INCREMENT=1171 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
