/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `insert_user_role_before` BEFORE INSERT ON `users` FOR EACH ROW BEGIN
  DECLARE roleCount INT DEFAULT 0;
  DECLARE rolePerms TEXT;
  DECLARE roleAccess TEXT;

  IF NEW.user_type IS NOT NULL AND NEW.user_type != 'Student' THEN

    
    SELECT COUNT(*) INTO roleCount
    FROM roles
    WHERE user_type = NEW.user_type
      AND school_id = NEW.school_id;

    IF roleCount = 0 THEN
      INSERT INTO roles (user_type, description, accessTo, permissions, school_id)
      SELECT user_type, description, accessTo, permissions, NEW.school_id
      FROM roles
      WHERE user_type = NEW.user_type
        AND school_id = 'SCH/1'
      LIMIT 1;
    END IF;

    
    SELECT permissions, accessTo
    INTO rolePerms, roleAccess
    FROM roles
    WHERE user_type = NEW.user_type
      AND school_id = NEW.school_id
    LIMIT 1;

    SET NEW.permissions = rolePerms;
    SET NEW.accessTo    = roleAccess;
  END IF;
END */;;
DELIMITER ;
